// Get Progress Summary v2
const execData = $('HTTP: Get Recent Executions').first().json;
const staticData = $('HTTP: Get Workflow StaticData').first().json;
const syscomData = $('HTTP: Check Syscom API').first().json;
const odooHealth = $('HTTP: Check Odoo Health').first().json;

const execs = execData.data || [];
const global = (staticData.staticData || {}).global || {};

const CATS = ["Videovigilancia","Redes","Radiocomunicación","Automatización e Intrusión",
    "Cableado Estructurado","Control de Acceso","Energía","Detección de Incendio",
    "Sonido y Video","Herramientas"];
const TOTAL_PAGES = 950;

const catIdx = Number(global.categoryIndex) || 0;
const page = Number(global.page) || 1;
// Approximate: each category has ~95 pages avg
const pagesPerCat = TOTAL_PAGES / CATS.length;
const approxPagesTotal = catIdx * pagesPerCat + page;
const pctComplete = Math.min(100, Math.round(approxPagesTotal / TOTAL_PAGES * 100));

const last24h = new Date(Date.now() - 24*60*60*1000).toISOString();
const recent = execs.slice(0, 20);
const errors24h = recent.filter(e => e.status !== 'success' && (e.startedAt || '') > last24h).length;
const last5 = recent.slice(0, 5).map(e => ({
    id: e.id, status: e.status,
    time: (e.startedAt || '').substring(11, 19)
}));

// Products processed estimate: pages done * 3 products avg per page
const approxProducts = Math.round(approxPagesTotal * 3);

// Syscom health
const syscomOk = !!(syscomData.productos || syscomData.access_token || Array.isArray(syscomData));
const odooOk = odooHealth.status === 'pass' || JSON.stringify(odooHealth).includes('ok');

// ETA: remaining pages * 5 min each / 60 = hours
const remaining = TOTAL_PAGES - approxPagesTotal;
const etaHours = Math.round(remaining * 5 / 60);

return [{ json: {
    catIdx, catName: CATS[catIdx] || 'Desconocida', page,
    pctComplete, approxPagesTotal, remaining,
    approxProducts, etaHours,
    errors24h, last5,
    syscomOk, odooOk,
    lastSave: global.lastSave || 'N/A',
    timestamp: new Date().toISOString()
}}];

const d = $input.item.json;
const p = d.progress;
const e = d.executions;
const h = d.health;
const eta = d.eta;

const syscomIcon = h.syscom === 'OK' ? '[OK]' : '[DOWN]';
const odooIcon   = h.odoo   === 'OK' ? '[OK]' : '[DOWN]';
const statusIcon = (s) => { if (s === 'success') return '[OK]'; if (s === 'error' || s === 'crashed') return '[ERR]'; if (s === 'running') return '[...]'; return '[?]'; };

const lastFiveHtml = e.lastFive.map(ex => { const started = ex.startedAt ? new Date(ex.startedAt).toISOString().slice(0,16).replace('T',' ') : 'N/A'; return '<tr><td style="padding:4px 8px;">' + statusIcon(ex.status) + ' ' + ex.status + '</td><td style="padding:4px 8px;">' + started + '</td><td style="padding:4px 8px;font-family:monospace;font-size:11px;">' + ex.id + '</td></tr>'; }).join('');

const alertColor = e.errorCount24h > 0 ? '#ff5252' : '#4CAF50';
const alertMsg = e.errorCount24h > 0 ? 'WARNING: ' + e.errorCount24h + ' error(s) in last 24h - review executions!' : 'OK - No errors in last 24h';

const progressWidth = Math.min(p.progressPct, 100);

const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{font-family:Arial,sans-serif;color:#333;max-width:640px;margin:0 auto;padding:20px;}h1{color:#1a73e8;border-bottom:2px solid #1a73e8;padding-bottom:8px;}h2{color:#555;font-size:16px;margin-top:24px;}table{border-collapse:collapse;width:100%;}th{background:#f5f5f5;padding:6px 8px;text-align:left;font-size:13px;}td{border-bottom:1px solid #eee;font-size:13px;}.card{background:#f9f9f9;border-radius:8px;padding:16px;margin:12px 0;border:1px solid #ddd;}.alert{background:' + alertColor + ';color:#fff;border-radius:6px;padding:10px 16px;margin:12px 0;}.stat{display:inline-block;text-align:center;padding:8px 16px;margin:6px;background:#e8f0fe;border-radius:6px;min-width:100px;}.stat-val{font-size:22px;font-weight:bold;color:#1a73e8;}.stat-lbl{font-size:11px;color:#888;}</style></head><body>'
  + '<h1>Syscom-Odoo Sync — Coordinator Report</h1>'
  + '<p style="color:#888;font-size:12px;">Generated: ' + new Date(d.timestamp).toISOString().slice(0,16).replace('T',' ') + ' UTC</p>'
  + '<div class="alert">' + alertMsg + '</div>'
  + '<h2>Sync Progress</h2>'
  + '<div class="card">'
  + '<div style="background:#e0e0e0;border-radius:4px;height:20px;width:100%;"><div style="background:#4CAF50;border-radius:4px;height:20px;width:' + progressWidth + '%;"></div></div>'
  + '<p style="text-align:center;margin:4px 0;font-size:13px;">' + p.progressPct + '%</p>'
  + '<div style="text-align:center;margin-top:12px;">'
  + '<div class="stat"><div class="stat-val">' + p.progressPct + '%</div><div class="stat-lbl">Complete</div></div>'
  + '<div class="stat"><div class="stat-val">' + p.productsSynced.toLocaleString() + '</div><div class="stat-lbl">Products Synced</div></div>'
  + '<div class="stat"><div class="stat-val">' + p.totalPagesProcessed + '/' + p.totalPages + '</div><div class="stat-lbl">Pages Done</div></div>'
  + '<div class="stat"><div class="stat-val">' + eta.hoursLeft + 'h</div><div class="stat-lbl">Est. Remaining</div></div>'
  + '</div>'
  + '<table style="margin-top:12px;"><tr><th>Field</th><th>Value</th></tr>'
  + '<tr><td>Current Category</td><td>' + p.categoryName + ' (index ' + p.categoryIndex + ')</td></tr>'
  + '<tr><td>Current Page</td><td>' + p.currentPage + '</td></tr>'
  + '<tr><td>Remaining Pages</td><td>' + eta.remainingPages + '</td></tr>'
  + '<tr><td>Est. Completion</td><td>' + eta.estimatedCompletion + '</td></tr>'
  + '<tr><td>Last StaticData Save</td><td>' + (p.lastSave || 'N/A') + '</td></tr>'
  + '</table></div>'
  + '<h2>API Health</h2>'
  + '<div class="card"><p>' + syscomIcon + ' <strong>Syscom API:</strong> ' + h.syscom + '</p><p>' + odooIcon + ' <strong>Odoo:</strong> ' + h.odoo + '</p></div>'
  + '<h2>Last 5 Executions</h2>'
  + '<div class="card"><table><tr><th>Status</th><th>Started At</th><th>Execution ID</th></tr>' + (lastFiveHtml || '<tr><td colspan="3">No executions found</td></tr>') + '</table></div>'
  + '<h2>Error Summary</h2>'
  + '<div class="card"><p>Errors in last 24h: <strong style="color:' + (e.errorCount24h > 0 ? '#f44336' : '#4CAF50') + '">' + e.errorCount24h + '</strong></p><p>Executions checked: <strong>' + e.totalChecked + '</strong></p></div>'
  + '<hr style="margin-top:32px;border:none;border-top:1px solid #eee;">'
  + '<p style="font-size:11px;color:#aaa;">Coordinator Agent — Syscom-Odoo Sync System | Ocean Tech</p>'
  + '</body></html>';

const subject = '[' + (e.errorCount24h > 0 ? 'ERRORS' : 'OK') + '] Syscom-Odoo Sync: ' + p.progressPct + '% complete - ' + new Date().toISOString().slice(0,10);

return [{ json: { subject, html, reportData: d } }];

